'use client';

import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Download } from 'lucide-react';
import { transactions } from '@/lib/data';
import { Button } from '../ui/button';
import { useCurrencySymbol } from '@/hooks/use-currency';
import { Skeleton } from '../ui/skeleton';

export function RecentTransactions() {
  const currencySymbol = useCurrencySymbol();
  const recentTransactions = transactions.slice(0, 10);

  const formatCurrency = (value: number) => {
    if (currencySymbol === null) {
      return <Skeleton className="h-5 w-20" />;
    }
    const formattedAmount = new Intl.NumberFormat('en-IN', {
      style: 'decimal',
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    }).format(value);
    const sym = currencySymbol || '₹';
    return `${sym}${formattedAmount}`;
  };

  return (
    <Card className="shadow-md">
      <CardHeader className="flex flex-row items-center py-4 border-b">
        <CardTitle className="text-lg font-bold text-[#1e293b]">Recent Transactions</CardTitle>
        <Button 
          variant="default" 
          size="sm" 
          className="ml-auto bg-gradient-to-r from-primary to-accent hover:opacity-95 text-white gap-2 px-4 rounded-md font-bold shadow-sm border-0"
        >
          <Download className="h-4 w-4" />
          Export
        </Button>
      </CardHeader>
      <CardContent className="p-0">
        <Table>
          <TableHeader className="bg-[#f8fafc]">
            <TableRow>
              <TableHead className="font-bold text-[#64748b]">Date</TableHead>
              <TableHead className="font-bold text-[#64748b]">Type</TableHead>
              <TableHead className="font-bold text-[#64748b]">Category</TableHead>
              <TableHead className="font-bold text-[#64748b]">Description</TableHead>
              <TableHead className="font-bold text-[#64748b]">Amount</TableHead>
              <TableHead className="font-bold text-[#64748b]">Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {recentTransactions.length > 0 ? (
              recentTransactions.map((transaction) => (
                <TableRow key={transaction.id} className="hover:bg-[#f1f5f9] transition-colors">
                  <TableCell className="font-medium text-[#475569]">
                    {transaction.date.toLocaleDateString()}
                  </TableCell>
                  <TableCell className="capitalize text-[#475569]">{transaction.type}</TableCell>
                  <TableCell className="text-[#475569]">{transaction.category}</TableCell>
                  <TableCell className="text-[#475569]">{transaction.description}</TableCell>
                  <TableCell className="font-bold text-[#1e293b]">
                    {formatCurrency(transaction.amount)}
                  </TableCell>
                  <TableCell>
                    <button className="text-[#64748b] hover:text-[#1e293b]">...</button>
                  </TableCell>
                </TableRow>
              ))
            ) : (
              <TableRow>
                <TableCell colSpan={6} className="h-32 text-center text-muted-foreground">
                  No transactions yet.
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </CardContent>
    </Card>
  );
}
