'use client';

import { RecentTransactions } from '@/components/dashboard/recent-transactions';
import { SummaryCard } from '@/components/dashboard/summary-card';
import { FeedbackCard } from '@/components/dashboard/feedback-card';
import { SpendingByCategoryChart } from '@/components/reports/spending-by-category-chart';
import { transactions } from '@/lib/data';
import { Wallet, TrendingUp, TrendingDown } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';

export default function DashboardPage() {
  const totalIncome = transactions
    .filter((t) => t.type === 'income')
    .reduce((acc, t) => acc + t.amount, 0);
  const totalExpenses = transactions
    .filter((t) => t.type === 'expense')
    .reduce((acc, t) => acc + t.amount, 0);
  const balance = totalIncome - totalExpenses;

  return (
    <div className="max-w-7xl mx-auto w-full space-y-6">
      {/* Summary Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <SummaryCard
          title="Total Balance"
          value={balance}
          icon={Wallet}
          variant="purple"
        />
        <SummaryCard
          title="Total Income"
          value={totalIncome}
          icon={TrendingUp}
          variant="green"
        />
        <SummaryCard
          title="Total Expenses"
          value={totalExpenses}
          icon={TrendingDown}
          variant="red"
        />
      </div>

      {/* Transactions Row */}
      <RecentTransactions />

      {/* Bottom Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 pb-10">
        <Card className="shadow-md">
          <CardHeader className="py-4">
            <CardTitle className="text-lg font-bold text-[#1e293b]">Income vs Expenses Distribution</CardTitle>
          </CardHeader>
          <CardContent className="h-[400px] flex items-center justify-center p-0">
             <SpendingByCategoryChart />
          </CardContent>
        </Card>

        <FeedbackCard />
      </div>
    </div>
  );
}
