'use client';

import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from '@/components/ui/chart';
import { categories, transactions } from '@/lib/data';
import { Pie, PieChart, Cell } from 'recharts';

const incomeTotal = transactions
  .filter((t) => t.type === 'income')
  .reduce((acc, t) => acc + t.amount, 0);

const expenseTotal = transactions
  .filter((t) => t.type === 'expense')
  .reduce((acc, t) => acc + t.amount, 0);

const chartData = [
  { name: 'Income', value: incomeTotal, fill: '#10b981' },
  { name: 'Expense', value: expenseTotal, fill: '#ef4444' },
].filter(d => d.value > 0);

const chartConfig = {
  value: {
    label: 'Amount',
  },
  Income: { label: 'Income', color: '#10b981' },
  Expense: { label: 'Expense', color: '#ef4444' },
} satisfies ChartConfig;

export function SpendingByCategoryChart() {
  return (
    <div className="w-full h-full flex items-center justify-center">
      {chartData.length > 0 ? (
        <ChartContainer
          config={chartConfig}
          className="mx-auto aspect-square h-[300px]"
        >
          <PieChart>
            <ChartTooltip
              cursor={false}
              content={<ChartTooltipContent hideLabel />}
            />
            <Pie
              data={chartData}
              dataKey="value"
              nameKey="name"
              innerRadius={60}
              strokeWidth={5}
            >
              {chartData.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={entry.fill} />
              ))}
            </Pie>
          </PieChart>
        </ChartContainer>
      ) : (
        <div className="w-64 h-64 rounded-full bg-[#f1f5f9] border-8 border-white shadow-inner flex items-center justify-center">
          <div className="w-32 h-px bg-[#e2e8f0] rotate-0" />
        </div>
      )}
    </div>
  );
}
